  ('disabled-57f41407-moex-00656', 'disabled-57f41407', 'disabled-57f41407-moex-110-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '乙委任甲為訴訟代理人，乙於委任書表示甲對於該本案有為所有訴訟行為 之權。關於甲得為之訴訟行為，下列敘述何者錯誤？', '["對於對造主張之事實為自認", "對於一審敗訴之判決提起上訴", "為預防對造脫產而聲請假扣押", "於期日偕同輔佐人到場"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "21ff34e8b3c0", "answer_pdf_sha1": "771e36403dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0407", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00657', 'disabled-57f41407', 'disabled-57f41407-moex-110-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於訴訟費用之擔保，下列敘述何者錯誤？', '["原告於中華民國無住所、事務所及營業所，法院得依職權裁定命原告供 訴訟費用之擔保", "法院已裁定命原告供訴訟費用之擔保，訴訟中發生擔保不足額之情事， 法院得依被告之聲請，裁定命原告供訴訟費用之擔保", "被告已為本案之言詞辯論者，法院原則上不得再裁定命原告供訴訟費用 之擔保", "關於命供擔保之裁定，得為抗告"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "21ff34e8b3c0", "answer_pdf_sha1": "771e36403dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0407", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00658', 'disabled-57f41407', 'disabled-57f41407-moex-110-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '下列何者，得以裁定更正原判決？', '["判決不備理由", "判決誤算原告列明之各項利息總額", "判決違背經驗法則", "判決未行言詞辯論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "21ff34e8b3c0", "answer_pdf_sha1": "771e36403dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0407", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00659', 'disabled-57f41407', 'disabled-57f41407-moex-110-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於送達之機關，下列敘述何者正確？', '["送達，由法院書記官交執達員或郵務機構行之", "送達，除別有規定外，由民事執行處法官依職權為之", "民事執行處書記官交由民間快遞機構送達者，其送達費用由當事人自行支出", "對在監獄之人為送達者，執達員應囑託該受刑人之家屬為之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "21ff34e8b3c0", "answer_pdf_sha1": "771e36403dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0407", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00660', 'disabled-57f41407', 'disabled-57f41407-moex-110-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於當事人書狀及其閱覽，下列敘述何者正確？', '["於當事人閱覽他造書狀發現不合程式者，應以言詞向書記官聲明要求對 方更正之。他造當事人逾期未更正者，視為未提出該書狀", "當事人之書狀不合程式者，法院應命其於 20 日不變期間內補正，否則 視為未提出該書狀", "當事人提出於法院之文件原本，僅他造訴訟代理人可聲請閱覽", "於言詞辯論外，關於訴訟所為之聲明，除依民事訴訟法應用書狀者外， 得於法院書記官前以言詞為之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "21ff34e8b3c0", "answer_pdf_sha1": "771e36403dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0407", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00661', 'disabled-57f41407', 'disabled-57f41407-moex-110-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '下列訴訟行為，何者不得於訴訟當然或裁定停止期間為之？', '["解除訴訟委任", "撤回起訴", "聲明承受訴訟", "聲請訴訟救助"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "21ff34e8b3c0", "answer_pdf_sha1": "771e36403dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0407", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00662', 'disabled-57f41407', 'disabled-57f41407-moex-110-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '甲依 A 法律關係對乙提起訴訟，乙欲以相牽連之 B 法律關係提起反訴， 而B法律關係對於甲與訴外人丙應合一確定。下列敘述何者正確？', '["乙不得提起反訴", "乙僅得以甲為反訴被告", "乙須向甲或丙之住所地法院提起反訴", "乙得以甲與丙為反訴之共同被告"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "21ff34e8b3c0", "answer_pdf_sha1": "771e36403dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0407", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00663', 'disabled-57f41407', 'disabled-57f41407-moex-110-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '甲將其所有之A屋出租予乙，乙屢屢欠租，甲遂以乙為被告，起訴請求給 付租金及返還租賃物。甲於訴訟進行中，將 A 屋出售給丙，並將與 A 屋 相關的債權讓與給丙。關於甲對乙之訴訟，下列敘述何者正確？', '["因丙為新出租人，所以丙為新原告，甲遂脫離訴訟", "甲仍為原告，並得為訴訟行為", "丙得不經乙之同意聲請承當訴訟", "丙一旦合法承當訴訟，甲即脫離訴訟，不受訴訟效力之拘束"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "21ff34e8b3c0", "answer_pdf_sha1": "771e36403dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0407", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00664', 'disabled-57f41407', 'disabled-57f41407-moex-110-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於訴訟上和解，下列敘述何者錯誤？', '["和解成立者，與確定終局判決有同一之效力", "法院僅得於第一審言詞辯論終結前，為當事人試行和解", "第三人經法院許可，得參加和解", "和解有無效或得撤銷之原因者，當事人得請求繼續審判"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "21ff34e8b3c0", "answer_pdf_sha1": "771e36403dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0407", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00665', 'disabled-57f41407', 'disabled-57f41407-moex-110-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於人證，下列敘述何者正確？', '["證人所為證言足致證人受刑事訴追者，得拒絕證言", "當事人不得聲請審判長對證人為必要之發問", "證人以書狀陳述者，於任何情形均無須具結", "聲明人證時無須表明證人及訊問之事項"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "21ff34e8b3c0", "answer_pdf_sha1": "771e36403dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0407", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL)
